from colorama import Fore, init
from argparse import ArgumentParser, RawTextHelpFormatter

# Initialize colorama
init()

class Storage:
    def __init__(self):
        self.tasks = []

    def save(self):
        with open('tasks.json', 'w') as f:
            json.dump(self.tasks, f, indent=2)

    def load(self):
        try:
            with open('tasks.json', 'r') as f:
                self.tasks = json.load(f)
        except FileNotFoundError:
            self.tasks = []

class Task:
    def __init__(self, title, description=None, priority='low', due_date=None, tags=None):
        self.title = title
        self.description = description
        self.priority = priority
        self.due_date = due_date
        self.tags = tags if tags else []
        self.completed = False

    def __repr__(self):
        return f"{self.title} - {self.description} (Priority: {self.priority}, Due: {self.due_date})"

    def __str__(self):
        return self.__repr__()

    def to_dict(self):
        return {
            'title': self.title,
            'description': self.description,
            'priority': self.priority,
            'due_date': self.due_date,
            'tags': self.tags,
            'completed': self.completed
        }

class TaskManager:
    def __init__(self, storage):
        self.storage = storage
        self.tasks = storage.load()

    def add_task(self, title, description=None, priority='low', due_date=None, tags=None):
        new_task = Task(title, description, priority, due_date, tags)
        self.tasks.append(new_task)
        self.storage.save()
        return new_task

    def mark_task(self, task_id, complete=True):
        for task in self.tasks:
            if task.id == task_id:
                task.completed = complete
                break

    def edit_task(self, task_id, title=None, description=None, priority=None, due_date=None, tags=None):
        for task in self.tasks:
            if task.id == task_id:
                if title is not None:
                    task.title = title
                if description is not None:
                    task.description = description
                if priority is not None:
                    task.priority = priority
                if due_date is not None:
                    task.due_date = due_date
                if tags is not None:
                    task.tags = tags
                task.to_dict()
                break

    def delete_task(self, task_id):
        for task in self.tasks:
            if task.id == task_id:
                self.tasks.remove(task)
                break

    def list_tasks(self, sort_by=None, filter_by=None):
        filtered_tasks = []
        if filter_by is not None:
            for task in self.tasks:
                if filter_by in task.tags and not task.completed:
                    filtered_tasks = [task.to_dict() for task in self.tasks if filter_by in task.tags]
        else:
            filtered_tasks = self.tasks.copy()

        if sort_by == 'priority':
            filtered_tasks.sort(key=lambda x: x['priority'])
        elif sort_by == 'due_date':
            filtered_tasks.sort(key=lambda x: x['due_date'])

        return filtered_tasks

class CLI:
    def __init__(self, task_manager):
        self.task_manager = task_manager
        self.parser = ArgumentParser(description='Task Manager CLI')
        self.parser.add_argument_group('Task Operations')
        self.parser.add_argument('--add', dest='add', action='store_true', help='Add a new task')
        self.parser.add_argument('--list', dest='list', action='store_true', help='List all tasks')
        self.parser.add_argument('--mark', dest='mark', type=int, nargs=2, help='Mark task as complete')
        self.parser.add_argument('--edit', dest='edit', type=int, nargs=2, help='Edit task details')
        self.parser.add_argument('--delete', dest='delete', type=int, help='Delete task by ID')
        self.parser.add_argument('--help', dest='help', action='store_true', help='Show help message')

    def run(self):
        self.parser.setHelp('Command-line Task Manager')
        self.parser.set epilogue help='Subcommands: add | list | mark | edit | delete | help | exit')

        args = self.parser.parse_args()

        if args.add:
            title = input("Enter task title: ")
            description = input("Enter task description (optional): ")
            priority = input("Enter task priority (low/medium/high): ")
            due_date = input("Enter task due date (YYYY-MM-DD): ")
            tags = input("Enter tags (comma-separated, optional): ").strip().split(',') if input().strip() else None

            if title:
                task = self.task_manager.add_task(title, description, priority, due_date, tags)
                print(f"{Fore.GREEN}Task added successfully: {task.title}{Fore.RESET}")

        if args.list:
            tasks = self.task_manager.list_tasks()
            print("\nCurrent Tasks:")
            for task in tasks:
                print(f"{Fore.BLUE}{task['title']} - {task['description']} (Priority: {task['priority)}, Due: {task['due_date']}){Fore.RESET}")

        if args.mark:
            task_id = args.mark[0]
            complete = args.mark[1]
            self.task_manager.mark_task(task_id, complete)

        if args.edit:
            task_id = args.edit[0]
            title = args.edit[1]
            if title:
                self.task_manager.edit_task(task_id, title=title)

        if args.delete:
            task_id = args.delete
            self.task_manager.delete_task(task_id)

if __name__ == "__main__":
    storage = Storage()
    task_manager = TaskManager(storage)
    cli = CLI(task_manager)
    cli.run()
