    def _validate_right(self, value: int) -> None:
        """Validate that the right subtree maintains BST property."""
        if value > node.value:
            raise ValueError("Invalid right child value.")

    def insert(self, value: int) -> None:
        """Insert a new node with the given value into the BST."""
        self._validate_value(value)

    def delete(self, value: int) -> None:
        """Delete the node with the given value from the BST."""
        self._validate_value(value)

    def search(self, value: int) -> bool:
        """Search for the given value in the BST."""
        current = self.root
        while current is not None and current.value != value:
            if value < current.value:
                current = current.left
            else:
                current = current.right
        return current is not None

    def __str__(self) -> str:
        """Return a string representation of the tree."""
        if self.root is None:
            return ""
        return self._serialize()

    def _serialize(self) -> str:
        """Serialize the tree using pre-order traversal."""
        result = []
        stack = [(self.root, False)]
        while stack:
            node, visited = stack.pop()
            if node is None:
                result.append("null")
                continue
            if visited:
                result.append(str(node.value))
            else:
                result.append(str(node.value))
                stack.append((node.right, False))
                stack.append((node.left, False))
        return ",".join(result)

    def deserialize(self, s: str) -> Optional['BinarySearchTree']:
