    def __init__(self, max_size: int = 0, ttl: int = -1, initial_capacity: int = 10000):
        """
        Initialize the InMemoryStore with optional parameters.

        :param max_size: Maximum number of key-value pairs to maintain (0 for unbounded)
        :param ttl: Time-to-Live in seconds; -1 for permanent
        :param initial_capacity: Initial capacity of the underlying dictionary
        """
