        self.timestamp = defaultdict(int)
        self counters = defaultdict(int)
        self.stack = []
        self.current_transaction_id = 0
        self._lock = threading.Lock()

    def __getitem__(self, key: Type) -> Type:
        """Allow dictionary-style access to the store."""
        with self._lock:
            return self.cache.get(key)

    def __setitem__(self, key: Type, value: Type) -> None:
        """Set or create a key-value pair."""
        with self._lock:
            self.cache[key] = value

    def __delitem__(self, key: Type) -> None:
        """Delete a key-value pair."""
        with self._lock:
            del self.cache[key]

    def get(self, key: Type, default: Type = None) -> Type:
        """Return the value for the key, or the default value if the key is not present."""
        with self._lock:
            return self.cache.get(key, default)

    def set(self, key: Type, value: Type) -> None:
        """Set or create a key-value pair with optional expiration."""
        with self._lock:
            current_time = time.time()
            if self.ttl == -1:
