    def insert(self, value):
        """Insert a new node with the given value into the BST."""
        if self.root is None:
            self.root = Node(value)
        else:
            self._insert_recursive(self.root, value)

    def _insert_recursive(self, node, value):
        """Helper method to insert a node recursively."""
        if value < node.value:
            if node.left is None:
                node.left = Node(value)
            else:
                self._insert_recursive(node.left, value)
        elif value > node.value:
            if node.right is None:
                node.right = Node(value)
            else:
                self._insert_recursive(node.right, value)
        # else: value is already present, do nothing or handle duplicates as needed

    def delete(self, value):
        """Delete a node with the given value from the BST."""
        if self.root is None:
            return
        self._delete_recursive(self.root, value)

    def _delete_recursive(self, node, value):
        """Helper method to delete a node recursively."""
        if value < node.value:
            if node.left is None:
                node.left = None
            else:
                self._delete_recursive(node.left, value)
        elif value > node.value:
            if node.right is None:
                node.right = None
            else:
                self._delete_recursive(node.right, value)
        else:
            if node.left and node.right:
                # Find the in-order successor
                successor = node.right
                while successor.left is not None:
                    successor = successor.left
                node.value = successor.value
                self._delete_recursive(successor, successor.value)
            elif node.left:
                node.left = None
            elif node.right:
                node.right = None
            else:
                node = None

    def search(self, value):
        """Search for a node with the given value in the BST."""
        return self._search_recursive(self.root, value)

    def _search_recursive(self, node, value):
        """Helper method to search for a value recursively."""
        if node is None or value == node.value:
            return node
        if value < node.value:
            return self._search_recursive(node.left, value)
        else:
            return self._search_recursive(node.right, value)

    def in_order_traversal(self):
        """Perform in-order traversal and return node values in a list."""
        return self._in_order_recursive(self.root)

    def _in_order_recursive(self, node):
        """Helper method to perform in-order traversal recursively."""
        if node is None:
            return []
        return self._in_order_recursive(node.left) + [node.value] + self._in_order_recursive(node.right)

    def pre_order_traversal(self):
        """Perform pre-order traversal and return node values in a list."""
        return self._pre_order_recursive(self.root)

    def _pre_order_recursive(self, node):
        """Helper method to perform pre-order traversal recursively."""
        if node is None:
            return []
        return [node.value] + self._pre_order_recursive(node.left) + self._pre_order_recursive(node.right)

    def post_order_traversal(self):
        """Perform post-order traversal and return node values in a list."""
        return self._post_order_recursive(self.root)

    def _post_order_recursive(self, node):
        """Helper method to perform post-order traversal recursively."""
        if node is None:
            return []
        return self._post_order_recursive(node.left) + self._post_order_recursive(node.right) + [node.value]

    def level_order_traversal(self):
        """Perform level-order traversal (BFS) and return node values in a list."""
        if self.root is None:
            return []
        queue = [self.root]
        result = []
